"use strict";(globalThis.webpackChunkdocusaurus_resource=globalThis.webpackChunkdocusaurus_resource||[]).push([[457],{416:e=>{e.exports=JSON.parse('{"tag":{"label":"level/beginner","permalink":"/accessibility-hub/docs/tags/level-beginner","allTagsPath":"/accessibility-hub/docs/tags","count":58,"items":[{"id":"for-users/by-disability-type/speech-language/stroke-aac-tools","title":"AAC Tools for Stroke Recovery","description":"Stroke survivors often experience aphasia, dysarthria, or motor impairments that affect communication. AAC tools can restore independence and improve quality of life.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-aac-tools"},{"id":"about/about","title":"About Accessibility Hub","description":"A brief introduction to the Accessibility HUB, its history, and the founder\u2019s motivation.","permalink":"/accessibility-hub/docs/about/about"},{"id":"hot-topics/accessibility-audit","title":"Accessibility Audit","description":"Accessibility Audit covers the process and tools for evaluating digital content for accessibility compliance. This page will be expanded and curated with more detailed guidance and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/accessibility-audit"},{"id":"about/overview","title":"Accessibility Hub Overview","description":"Accessibility Hub Overview","permalink":"/accessibility-hub/docs/about/overview"},{"id":"hot-topics/accessibility-testing","title":"Accessibility Testing","description":"Accessibility Testing covers the tools, methods, and best practices for evaluating digital content for accessibility. This page will be expanded and curated with more detailed guidance and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/accessibility-testing"},{"id":"for-users/by-disability-type/vision/e-readers","title":"Accessible E-Readers","description":"Accessible e-readers","permalink":"/accessibility-hub/docs/for-users/by-disability-type/vision/e-readers"},{"id":"for-developers/accessible-web-dev-checklist","title":"Accessible Web Development Checklist","description":"A comprehensive checklist based on WCAG 2.1 Level AA and best practices from W3C, WebAIM, and Section508.gov.","permalink":"/accessibility-hub/docs/for-developers/accessible-web-dev-checklist"},{"id":"for-users/by-disability-type/aging-dexterity/external-resources","title":"Aging & Dexterity - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/aging-dexterity/external-resources"},{"id":"hot-topics/alt-text-ai","title":"Alt Text AI","description":"Alt Text AI is a tool or concept related to generating or improving alternative text for images using artificial intelligence. This page will be expanded and curated with more detailed content in the future to help users understand and leverage AI for accessible image descriptions.","permalink":"/accessibility-hub/docs/hot-topics/alt-text-ai"},{"id":"for-users/by-disability-type/mobility/aphasia-communication-quickstart","title":"Aphasia Communication Quick Start for Caregivers","description":"Stroke Communication Support Guide for Caregivers, for a person who cannot speak, cannot read or write, prefers sound, and can use a touchscreen or gestures.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/mobility/aphasia-communication-quickstart"},{"id":"hot-topics/aria-roles","title":"ARIA Roles","description":"ARIA Roles define the purpose of elements in web content for assistive technologies. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/aria-roles"},{"id":"hot-topics/bug-bounty","title":"Bug Bounty","description":"Bug Bounty programs encourage the discovery and reporting of accessibility issues. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/bug-bounty"},{"id":"for-users/by-disability-type/speech-language/stroke-caregiver-guide","title":"Caregiver Guide for Post-Stroke Communication","description":"Supporting a loved one after stroke involves patience, creativity, and knowledge of communication strategies.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-caregiver-guide"},{"id":"for-users/by-disability-type/cognitive/external-resources","title":"Cognitive - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/cognitive/external-resources"},{"id":"hot-topics/color-contrast","title":"Color Contrast","description":"Color Contrast is essential for readability and accessibility, especially for users with visual impairments. This page will be expanded and curated with more information and best practices in the future.","permalink":"/accessibility-hub/docs/hot-topics/color-contrast"},{"id":"resources/communities-groups","title":"Communities & Groups","description":"Learning is better together. Join these communities to ask questions and share knowledge.","permalink":"/accessibility-hub/docs/resources/communities-groups"},{"id":"for-users/by-disability-type/vision/companies","title":"Companies Committed to Accessibility (Vision)","description":"Companies committed to accessibility","permalink":"/accessibility-hub/docs/for-users/by-disability-type/vision/companies"},{"id":"resources/learning-paths/courses-programs","title":"Courses & Programs","description":"A mix of free and paid courses from trusted organizations.","permalink":"/accessibility-hub/docs/resources/learning-paths/courses-programs"},{"id":"hot-topics/dyslexia-support","title":"Dyslexia Support","description":"Dyslexia Support covers tools and strategies to assist individuals with dyslexia. This page will be expanded and curated with more resources and best practices in the future.","permalink":"/accessibility-hub/docs/hot-topics/dyslexia-support"},{"id":"community/events","title":"Events & Hackathons","description":"Calendar of upcoming accessibility events, hackathons, and webinars.","permalink":"/accessibility-hub/docs/community/events"},{"id":"for-developers/external-resources","title":"for Developers - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-developers/external-resources"},{"id":"community/forums","title":"Forums or Discussions","description":"Open forums for sharing experiences, troubleshooting, and networking.","permalink":"/accessibility-hub/docs/community/forums"},{"id":"community-contributions/getting-started","title":"Getting Started","description":"1. Fork & clone.","permalink":"/accessibility-hub/docs/community-contributions/getting-started"},{"id":"hot-topics/github-access-tools","title":"GitHub Access Tools","description":"GitHub Access Tools are resources and utilities to improve accessibility for developers and users on GitHub. This page will be expanded and curated with more information in the future.","permalink":"/accessibility-hub/docs/hot-topics/github-access-tools"},{"id":"resources/free-oss-resources","title":"Guides, Open source Tools and Patterns","description":"A curated list of high-quality, no-cost guides, tools, and patterns.","permalink":"/accessibility-hub/docs/resources/free-oss-resources"},{"id":"for-users/by-disability-type/hearing/external-resources","title":"Hearing - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/hearing/external-resources"},{"id":"use-cases/home","title":"Home and Daily Life Scenarios","description":"Home and Daily Life Scenarios","permalink":"/accessibility-hub/docs/use-cases/home"},{"id":"for-developers/how-to-contribute","title":"How to contribute","description":"Developers play a crucial role in making the world more accessible by designing and building digital experiences that are inclusive of people with disabilities. Here are several impactful ways developers can contribute:","permalink":"/accessibility-hub/docs/for-developers/how-to-contribute"},{"id":"use-cases/future","title":"Hypothetical/Future Scenarios","description":"Hypothetical/Future Scenarios","permalink":"/accessibility-hub/docs/use-cases/future"},{"id":"hot-topics/inclusive-design","title":"Inclusive Design","description":"Inclusive Design is about creating products and experiences that are accessible to as many people as possible. This page will be expanded and curated with more resources and examples in the future.","permalink":"/accessibility-hub/docs/hot-topics/inclusive-design"},{"id":"hot-topics/langchain4j-tools","title":"LangChain4J Tools","description":"LangChain4J Tools are resources for integrating language models and AI into Java applications. This page will be expanded and curated with more information and examples in the future.","permalink":"/accessibility-hub/docs/hot-topics/langchain4j-tools"},{"id":"resources/legal-standards","title":"Legal standards","description":"Legal & Standards Overview","permalink":"/accessibility-hub/docs/resources/legal-standards"},{"id":"community-contributions/FRONTMATTER_GUIDE","title":"Metadata for Resources (Frontmatter) guide","description":"Every file must include a frontmatter section (YAML metadata) to classify and describe the resource. This helps us organize the hub and ensures your contribution integrates seamlessly into our systems.","permalink":"/accessibility-hub/docs/community-contributions/FRONTMATTER_GUIDE"},{"id":"for-users/by-disability-type/mobility/external-resources","title":"Mobility - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/mobility/external-resources"},{"id":"for-users/by-disability-type/neurodiversity/external-resources","title":"Neurodiversity - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/neurodiversity/external-resources"},{"id":"hot-topics/nlp-assist","title":"NLP Assist","description":"NLP Assist refers to the use of Natural Language Processing to support accessibility and user interaction. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/nlp-assist"},{"id":"hot-topics/otter-ai","title":"Otter.ai","description":"Otter.ai is a tool for real-time transcription and captioning. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/otter-ai"},{"id":"resources/learning-paths/quickstart-guide","title":"Quickstart Guide with FOSS","description":"This plan is designed to get you hands-on with core accessibility concepts in one week, using freely available, and wherever possible, open-source tools.","permalink":"/accessibility-hub/docs/resources/learning-paths/quickstart-guide"},{"id":"hot-topics/real-time-captions","title":"Real-time Captions","description":"Real-time Captions provide instant text transcriptions of spoken content, improving accessibility for users who are deaf or hard of hearing. This page will be expanded and curated with more information and resources in the future.","permalink":"/accessibility-hub/docs/hot-topics/real-time-captions"},{"id":"resources/research","title":"Research & Whitepapers","description":"Research and whitepapers on accessibility, AI, and assistive technology. (Content to be expanded based on future contributions and curation.)","permalink":"/accessibility-hub/docs/resources/research"},{"id":"about/roadmap","title":"Roadmap","description":"- [ ] Add tool reviews by disability.","permalink":"/accessibility-hub/docs/about/roadmap"},{"id":"for-users/by-disability-type/vision/screen-readers","title":"Screen Readers","description":"Screen readers turn text and interface elements into speech or Braille, opening up the digital world for people with vision loss.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/vision/screen-readers"},{"id":"hot-topics/seeing-ai","title":"Seeing AI","description":"Seeing AI is a Microsoft app that narrates the world for people with visual impairments. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/seeing-ai"},{"id":"hot-topics/smart-homes","title":"Smart Homes","description":"Smart Homes leverage technology to improve accessibility and independence for people with disabilities. More curated content and practical guidance will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/smart-homes"},{"id":"for-users/by-disability-type/speech-language/external-resources","title":"Speech & Language - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/external-resources"},{"id":"hot-topics/springai-assistive","title":"SpringAI Assistive","description":"SpringAI Assistive is a framework or tool for integrating AI-powered accessibility features. More curated content and examples will be added to this page in the future.","permalink":"/accessibility-hub/docs/hot-topics/springai-assistive"},{"id":"for-users/by-disability-type/speech-language/stroke-communication-checklist","title":"Stroke Communication Needs Checklist","description":"This checklist helps caregivers and professionals assess the communication abilities of individuals recovering from stroke. It supports the selection of appropriate AAC tools and therapy strategies.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-communication-checklist"},{"id":"for-users/by-disability-type/speech-language/stroke-profile-questionnaire","title":"Stroke Communication Profile Questionnaire","description":"Use this questionnaire to assess the communication needs of individuals recovering from stroke. Responses help match AAC tools, therapy strategies, and caregiver supports.","permalink":"/accessibility-hub/docs/for-users/by-disability-type/speech-language/stroke-profile-questionnaire"},{"id":"community/success-stories","title":"Success Stories","description":"Real-world examples of accessibility breakthroughs and user impact.","permalink":"/accessibility-hub/docs/community/success-stories"},{"id":"community-contributions/interview-template","title":"Testimony Interview Template","description":"Accessibility Testimony Interview Template","permalink":"/accessibility-hub/docs/community-contributions/interview-template"},{"id":"community-contributions/to-do-list","title":"To-Do List","description":"- [ ] Research AI accessibility tools.","permalink":"/accessibility-hub/docs/community-contributions/to-do-list"},{"id":"resources/tool-directory","title":"Tool Directory","description":"| Tool              | Type             | Tags                         | Link                                        |","permalink":"/accessibility-hub/docs/resources/tool-directory"},{"id":"community-contributions/TOPICS_GUIDE","title":"Topics Guide","description":"1. List of Existing Keywords/Topics","permalink":"/accessibility-hub/docs/community-contributions/TOPICS_GUIDE"},{"id":"community/personas","title":"User Personas","description":"Blind Developer","permalink":"/accessibility-hub/docs/community/personas"},{"id":"for-users/by-disability-type/vision/external-resources","title":"Vision - External Resources","description":"External Resources","permalink":"/accessibility-hub/docs/for-users/by-disability-type/vision/external-resources"},{"id":"hot-topics/voice-navigation","title":"Voice Navigation","description":"Voice Navigation explores the use of voice commands and speech recognition to navigate digital interfaces. More content will be added and curated in the future to provide comprehensive guidance and resources on this topic.","permalink":"/accessibility-hub/docs/hot-topics/voice-navigation"},{"id":"community-contributions/whats-missing","title":"What\u2019s Missing?","description":"Help us grow! Reviews, benchmarks, tutorials, case studies, open-source tests.","permalink":"/accessibility-hub/docs/community-contributions/whats-missing"},{"id":"use-cases/work","title":"Work-Related Use Cases","description":"Work-Related Use Cases","permalink":"/accessibility-hub/docs/use-cases/work"}],"unlisted":false}}')}}]);